// ============================================================
// VALIDADOR SQL — DEFENSA EN PROFUNDIDAD
// Capa 1: Allowlist (solo SELECT)
// Capa 2: Denylist de tokens peligrosos
// Capa 3: Validación estructural
// Capa 4: LIMIT forzado
// ============================================================

const raw = ($input.first().json.sql_query || '').toString();

// --- Helpers ---
const reject = (reason) => [{
  json: {
    valid: false,
    error: 'Query rechazado por seguridad',
    reason_internal: reason,
    sql_query: ''
  }
}];

// --- 0. Sanity checks básicos ---
if (!raw || typeof raw !== 'string') return reject('empty_or_invalid_type');
if (raw.length > 5000) return reject('too_long');
if (raw.length < 10) return reject('too_short');

// Trim y normalizar espacios
let sql = raw.trim();

// Quitar punto y coma final si lo trae
sql = sql.replace(/;+\s*$/g, '').trim();

// --- 1. ALLOWLIST: solo SELECT al inicio ---
if (!/^\s*SELECT\s/i.test(sql)) {
  return reject('not_a_select');
}

// --- 2. DENYLIST: tokens peligrosos ---
// Buscamos como palabras completas (\b) para no falsos positivos
const denyPatterns = [
  /\bINSERT\b/i,
  /\bUPDATE\b/i,
  /\bDELETE\b/i,
  /\bDROP\b/i,
  /\bALTER\b/i,
  /\bTRUNCATE\b/i,
  /\bCREATE\b/i,
  /\bGRANT\b/i,
  /\bREVOKE\b/i,
  /\bMERGE\b/i,
  /\bCALL\b/i,
  /\bEXEC\b/i,
  /\bEXECUTE\b/i,
  /\bCOPY\b/i,
  /\\copy/i,
  /\bDO\s+\$\$/i,
  /\bRETURNING\b/i,
  // Funciones peligrosas de Postgres
  /\bpg_sleep\b/i,
  /\bpg_read_file\b/i,
  /\bpg_ls_dir\b/i,
  /\blo_import\b/i,
  /\blo_export\b/i,
  /\bdblink\b/i,
  /\bcurrent_setting\b/i,
  /\bset_config\b/i,
  // Cosas raras de SQL Server / MySQL por si acaso
  /\bxp_\w+/i,
  /\bsp_executesql\b/i,
  /\bINTO\s+OUTFILE\b/i,
  /\bLOAD_FILE\b/i,
  // Stacked queries / comentarios
  /;/,
  /--/,
  /\/\*/,
  /\*\//,
  // System catalogs sensibles
  /\bpg_shadow\b/i,
  /\bpg_authid\b/i,
  /\bpg_user\b/i,
  /\binformation_schema\.\s*\w*password/i
];

for (const pattern of denyPatterns) {
  if (pattern.test(sql)) {
    return reject('denied_token:' + pattern.source);
  }
}

// --- 3. VALIDACIÓN ESTRUCTURAL ---

// Solo una sentencia (chequeo redundante con el de ; pero por si acaso)
const statementCount = (sql.match(/SELECT/gi) || []).length;
// Permitimos subqueries pero limitamos el anidamiento extremo
if (statementCount > 5) {
  return reject('too_many_selects');
}

// Debe consultar las tablas permitidas (allowlist de tablas)
const allowedTables = /\b(hey_transacciones|hey_productos|categorias_acciones)\b/i;
if (!allowedTables.test(sql)) {
  return reject('no_allowed_table_referenced');
}

// Bloquear acceso a tablas/esquemas de sistema
if (/\b(pg_catalog|pg_\w+|information_schema)\b/i.test(sql)) {
  return reject('system_catalog_access');
}

// Paréntesis balanceados (anti-evasion básica)
const open = (sql.match(/\(/g) || []).length;
const close = (sql.match(/\)/g) || []).length;
if (open !== close) {
  return reject('unbalanced_parens');
}

// Comillas balanceadas (cuenta simples no escapadas)
const singleQuotes = (sql.match(/'/g) || []).length;
if (singleQuotes % 2 !== 0) {
  return reject('unbalanced_quotes');
}

// --- 4. FORZAR LIMIT ---
// Si no trae LIMIT, le agregamos uno máximo
let finalSql = sql;
if (!/\bLIMIT\s+\d+/i.test(finalSql)) {
  finalSql = finalSql + ' LIMIT 1000';
} else {
  // Si trae LIMIT pero es absurdo, lo capamos
  finalSql = finalSql.replace(/\bLIMIT\s+(\d+)/i, (m, n) => {
    const num = parseInt(n, 10);
    return 'LIMIT ' + Math.min(num, 1000);
  });
}

// --- OK ---
return [{
  json: {
    valid: true,
    sql_query: finalSql,
    original_length: raw.length,
    final_length: finalSql.length
  }
}];
